import{_ as d}from"./chunks/demo-doc.NIuiqrK9.js";import{c as t,Q as r,j as o,m as a}from"./chunks/framework.BkjtU8k0.js";const D=JSON.parse('{"title":"概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/overview.md","filePath":"guide/overview.md","lastUpdated":1780018488000}'),i={name:"guide/overview.md"};function c(s,e,l,h,p,f){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><p>Flyfish Viewer 可以为业务系统快速补齐文件在线预览能力。它不同于依赖后端转码的方案，核心解析和渲染都在浏览器端完成，不会额外占用服务器执行 Office 转 PDF、临时文件清理或异步转换任务。</p><p>这让它特别适合静态部署、内网私有化、低运维成本和多系统复用场景。查看<a href="/guide/quickstart">快速开始</a>可以直接跑通第一个预览示例。</p><h2 id="当前能力" tabindex="-1">当前能力 <a class="header-anchor" href="#当前能力" aria-label="Permalink to &quot;当前能力&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>多格式预览</h3><p>内置 135 个扩展名映射，覆盖 Word、Excel、PowerPoint、PDF、OFD、压缩包、邮件、OLB/DRA、CAD、3D 模型、Excalidraw、draw.io、EPUB、UMD、Markdown、图片、音频、视频以及代码/文本。</p></div><div class="doc-card"><h3>纯前端渲染</h3><p>大部分格式不需要后端转码服务。业务侧只需要提供可访问 URL、File 或二进制数据包装后的 File。</p></div><div class="doc-card"><h3>按需异步加载</h3><p>PDF、OFD、压缩包、邮件、OLB/DRA、CAD、3D 模型、绘图、Office、EPUB、UMD、Markdown 和代码高亮都按需进入对应预览链路，减少无关格式的加载成本。</p></div><div class="doc-card"><h3>多接入路线</h3><p>Vue3 和 Vue2.7 都有对应 npm 包；两个安装器都会自动带上样式。React、纯 JS 和跨技术栈场景通过 iframe 复用 Vue3 基线 viewer 静态产物。</p></div></div><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>交付边界清楚。</strong> 组件、Demo、文档站、公开成品仓库、npm tarball 和构建脚本都围绕成品交付维护，接入方可以先验收效果再决定集成方式。</li><li><strong>视觉体验更接近真实阅读。</strong> Word 文档使用灰色页面底和白色纸张；PDF 提供缩放、页码、导航窗格和可视宽度自适应，避免打开后内容被挤压或不可读。</li><li><strong>格式策略务实。</strong> PPTX 重点增强组合图形、主题背景、图片裁剪和 EMF 矢量图片；OFD 基于 <code>DLTech21/ofd.js</code> 源码链路预览；压缩包用 <code>libarchive.js</code> Worker 按需解压内部文件；邮件用 <code>postal-mime</code> / <code>@kenjiuno/msgreader</code> 解析正文和附件；OLB/DRA 用 <code>cfb</code> 做结构树、对象候选、属性和诊断预览；CAD 支持 DXF，DWG 会尽量识别 DXF 误命名和提取内嵌预览图；3D 模型基于 Three.js 支持常见浏览器可渲染格式；Excalidraw 和 draw.io 使用官方预览能力；EPUB 使用 <code>epubjs</code>；UMD 电子书按文件结构解析元数据、目录和 zlib 正文段；音频使用浏览器原生播放器；代码/日志使用 <code>highlight.js</code> 轻量高亮，HTML 按源码展示。内置 CAD、3D、绘图、压缩包、邮件、EDA、UMD、音频和 EPUB 回归样例来源清楚，方便复现实文件兼容问题。</li><li><strong>适合平台复用。</strong> 多个系统可以共用同一套私有化 viewer 静态产物，只要升级静态资源即可统一更新预览能力。</li><li><strong>Vue2 / Vue3 / React / 纯 JS 同步维护。</strong> Vue3 包是 <code>@flyfish-group/file-viewer3@1.0.14</code>，Vue2 包是 <code>@flyfish-group/file-viewer@1.0.14</code>，React 包是 <code>@flyfish-group/file-viewer-react@1.0.14</code>，纯 JS 包是 <code>@flyfish-group/file-viewer-web@1.0.14</code>。Vue3 和 Vue2 安装器都会自动带入样式；React 和纯 JS 包不复制渲染器，只通过 iframe 加载 Vue3 基线产物。</li><li><strong>二开路径明确。</strong> 公开仓库提供成品下载，源码和商业二开通过 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a> 自助开通，避免交付渠道混乱。</li></ul><h2 id="关键特性" tabindex="-1">关键特性 <a class="header-anchor" href="#关键特性" aria-label="Permalink to &quot;关键特性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>Word</td><td><code>docx</code> 使用 <code>docx-preview</code>，<code>.doc</code> 使用 <code>msdoc-viewer</code>，保留文档页面感</td></tr><tr><td>Excel</td><td>多种表格格式统一进入表格预览链路，保留常见尺寸、合并和样式</td></tr><tr><td>PowerPoint</td><td>PPTX 增强组合图形坐标、旋转/翻转、主题背景、图片裁剪和 EMF 矢量图预览</td></tr><tr><td>PDF</td><td>基于 <code>pdfjs-dist</code>，支持缩放工具栏、页码状态、导航窗格、宽度适配、完整打印和导出 HTML</td></tr><tr><td>操作栏</td><td>支持下载原文件、打印完整渲染结果、导出渲染后 HTML，以及文字或图片水印</td></tr><tr><td>OFD</td><td>使用 <code>DLTech21/ofd.js</code> 源码链路，重型能力按需加载</td></tr><tr><td>压缩包</td><td>使用 <code>libarchive.js</code> Worker 读取目录，内部文件按需解压、缓存并继续在线预览</td></tr><tr><td>邮件</td><td>EML / MSG 支持头信息、HTML/文本正文、附件下载和附件继续预览</td></tr><tr><td>EDA</td><td>OLB / DRA 使用 CFB 容器解析、结构树、对象候选、属性和可读字符串索引，适合结构初筛</td></tr><tr><td>CAD</td><td>支持 DXF 图纸预览，提供缩放、平移和图层控制；DWG 尽量展示内嵌预览图</td></tr><tr><td>3D 模型</td><td>使用 Three.js 交互渲染 GLTF/GLB、OBJ、STL、PLY、FBX、DAE、3DS、3MF、AMF、USD/USDZ、KMZ、点云和 VTK 等格式</td></tr><tr><td>绘图</td><td>Excalidraw 使用官方 <code>restore</code> + <code>exportToSvg</code>，draw.io 使用官方 diagrams.net <code>GraphViewer</code></td></tr><tr><td>电子书</td><td>EPUB 使用 <code>epubjs</code>，UMD 解析移动电子书封装、目录和压缩正文</td></tr><tr><td>代码/文本</td><td>使用 <code>highlight.js</code> 高亮多语言源码、日志、配置和 diff</td></tr><tr><td>图片/音频/视频</td><td>图片使用浏览器原生能力和轻量查看器，音频和 MP4 使用原生媒体播放</td></tr></tbody></table><h2 id="成品与源码" tabindex="-1">成品与源码 <a class="header-anchor" href="#成品与源码" aria-label="Permalink to &quot;成品与源码&quot;">​</a></h2><p>公开 GitHub 仓库用于分发可直接下载使用的构建产物和示例，不包含源码目录。需要源码、二开包或商业自助开通的用户，可以前往 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a>，付费 4.99 后自助开通。</p><p>项目遵循 <code>Apache-2.0</code> 许可证。二开或商用时，请保留许可证、版权和来源说明，并注明项目来源为 Flyfish Viewer / <code>@flyfish-group/file-viewer3</code> 或 <code>@flyfish-group/file-viewer</code>。如果你基于项目修复了通用问题或增强了通用能力，也欢迎一起贡献。</p><div class="doc-shot"><img src="'+d+'" alt="DOC 文档按 Word 风格展示"><p class="doc-caption">Word 预览在视觉上回到灰色工作台与白色纸张的阅读模型，用户打开正式文档时会更接近熟悉的文档软件体验。</p></div>',13)])])}const v=t(i,[["render",c]]);export{D as __pageData,v as default};
